  1	import { ChartDonut, ChartLabel, ChartLegend } from '@patternfly/react-charts';
  2	import * as React from 'react';
  3	import { ControlPlane } from 'types/Mesh';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	
  6	type Props = {
  7	  controlPlanes: ControlPlane[];
  8	};
  9	
 10	export const infoStyle = kialiStyle({
 11	  margin: '0 0 -0.125rem 0.25rem'
 12	});
 13	
 14	export const ControlPlaneDonut: React.FC<Props> = ({ controlPlanes }) => {
 15	  const total = controlPlanes.reduce((acc, cp) => acc + (cp.managedNamespaces?.length || 0), 0);
 16	  const [hoveredSlice, setHoveredSlice] = React.useState<number | undefined>(undefined);
 17	  // Sorting so that the positions of the donut slices don't change on re-render.
 18	  // We can't sort the legendData because that includes the ':' char in the name
 19	  // which messes up the sort order.
 20	  controlPlanes.sort((a, b) => a.istiodName.localeCompare(b.istiodName));
 21	  const legendData = controlPlanes.map(cp => ({
 22	    name: `${cp.istiodName}:`,
 23	    subtext: ` ${cp.managedNamespaces ? cp.managedNamespaces.length : 0}`
 24	  }));
 25	
 26	  // Using a custom label here because there's no way to bold part of the text otherwise.
 27	  // This let's us break the text into two parts and apply separate styles to each so
 28	  // we can bold the first part and leave the second normal.
 29	  // e.g. <strong>1-21-1:</strong> 4
 30	  const label = (
 31	    <ChartLabel
 32	      inline={true}
 33	      style={[{ fontWeight: 'bold' }, { fontWeight: 'inherit' }]}
 34	      text={({ datum }) => [datum.name, datum.subtext] as any}
 35	    />
 36	  );
 37	
 38	  // Using a custom legendComponent so that we can pass custom data through to
 39	  // the custom labelComponent. Otherwise the label component will only get
 40	  // the name as the datum.
 41	  const legend = <ChartLegend labelComponent={label} data={legendData} />;
 42	
 43	  // This shows the number of namespaces inside the donut.
 44	  // It will update based on what slice you are hovering over.
 45	  const title =
 46	    hoveredSlice !== undefined && controlPlanes.at(hoveredSlice)
 47	      ? controlPlanes[hoveredSlice].managedNamespaces?.length || 0
 48	      : total;
 49	  const height = 180;
 50	  const width = 300;
 51	  return (
 52	    <div data-test="controlplane-donut">
 53	      <div>Namespaces managed by Control Planes</div>
 54	      <div style={{ height: `${height}px`, width: `${width}px` }}>
 55	        <ChartDonut
 56	          constrainToVisibleArea
 57	          style={{
 58	            data: {
 59	              // This will highlight the hovered slice on the donut
 60	              // by making the rest of the slices
 61	              // that aren't hovered more opaque.
 62	              opacity: ({ index }) => (hoveredSlice !== undefined && hoveredSlice !== index ? 0.3 : 1.0)
 63	            }
 64	          }}
 65	          height={height}
 66	          width={width}
 67	          // Padding is used to "center" the chart svg underneath the title
 68	          padding={{
 69	            top: 20,
 70	            left: 100,
 71	            bottom: 20,
 72	            right: 0
 73	          }}
 74	          data={controlPlanes}
 75	          events={[
 76	            {
 77	              target: 'data',
 78	              eventHandlers: {
 79	                onMouseEnter: (_, props) => {
 80	                  setHoveredSlice(props.index);
 81	                },
 82	                onMouseLeave: () => {
 83	                  setHoveredSlice(undefined);
 84	                }
 85	              }
 86	            }
 87	          ]}
 88	          labels={({ datum }) =>
 89	            `${datum.istiodName}: ${(((datum.managedNamespaces?.length || 0) / total) * 100).toFixed(2)}%`
 90	          }
 91	          legendData={legendData}
 92	          legendComponent={legend}
 93	          legendOrientation="vertical"
 94	          title={`${title}`}
 95	          subTitle="namespaces"
 96	          sortOrder="ascending"
 97	          x="istiodName"
 98	          y={datum => datum.managedNamespaces?.length || 0}
 99	        />
100	      </div>
101	    </div>
102	  );
103	};

